"use client";

import { useCallback, useEffect, useMemo } from "react";
import { useRouter, useParams } from "next/navigation";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";
import { PageSection } from "@ui/components/layout";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { api } from "@/lib/api";
import {
  CategoryFormShell,
  useCategoryForm,
  useCategoriesOptionsQuery,
  useCategoryDetailQuery,
  buildCategoryOptionTree,
  buildCategoryPayload,
} from "../../_component";
import type { CategoryFormValues } from "../../_component";

function EditCategoryPageInner() {
  const router = useRouter();
  const params = useParams();
  const categoryId = params.id as string;
  const queryClient = useQueryClient();
  const { form } = useCategoryForm();

  const { data: category, isLoading, isError, refetch } = useCategoryDetailQuery(api, categoryId);
  const categoriesOptionsQuery = useCategoriesOptionsQuery(api);

  const categoryTreeOptions = useMemo(
    () => buildCategoryOptionTree(categoriesOptionsQuery.data ?? []),
    [categoriesOptionsQuery.data],
  );

  useEffect(() => {
    if (isError) {
      toast.error("Không tải được danh mục");
      router.push("/categories");
    }
  }, [isError, router]);

  useEffect(() => {
    if (!category) return;
    form.reset({
      name: category.name ?? "",
      slug: category.slug ?? "",
      description: category.description ?? "",
      icon: category.icon ?? "Package2",
      sortOrder: category.sortOrder ?? 0,
      parentId: category.parentId ?? "__root__",
    });
  }, [category, form]);

  const invalidateAll = async () => {
    await queryClient.invalidateQueries({ queryKey: ["categories"] });
  };

  const updateMutation = useMutation({
    mutationFn: async (input: Record<string, unknown>) =>
      api.categories.update(categoryId, input as Parameters<typeof api.categories.update>[1]),
    onSuccess: async (_data, variables) => {
      await invalidateAll();
      toast.success(`Đã cập nhật danh mục "${(variables.name as string)?.trim()}"`);
      router.push(`/categories/${categoryId}`);
    },
    onError: (err: unknown) => {
      const message = err instanceof Error ? err.message : "Không thể cập nhật danh mục";
      toast.error(message);
    },
  });

  const handleSubmit = useCallback(
    async (values: CategoryFormValues) => {
      await updateMutation.mutateAsync(buildCategoryPayload(values));
    },
    [updateMutation],
  );

  if (isLoading) {
    return (
      <PageSection max="full" className="min-w-0 flex items-center justify-center py-24">
        <Loader2 className="size-8 animate-spin text-muted-foreground" />
      </PageSection>
    );
  }

  if (!category) return null;

  return (
    <PageSection max="full" className="min-w-0 space-y-6">
      <CategoryFormShell
        form={form}
        onSubmit={handleSubmit}
        submitting={updateMutation.isPending}
        editingId={categoryId}
        categoryTreeOptions={categoryTreeOptions}
        onBack={() => router.push(`/categories/${categoryId}`)}
        onReset={async () => {
          await refetch();
        }}
      />
    </PageSection>
  );
}

export default function EditCategoryPage() {
  return (
    <AdminPageGuard roles={["super_admin", "admin", "manager"]}>
      <EditCategoryPageInner />
    </AdminPageGuard>
  );
}

src/app/categories/_component/columns.ts.content:
"use client";

import type { ColumnDef } from "@tanstack/react-table";
import { Button } from "@ui/components/button";
import { Badge } from "@ui/components/badge";
import { Eye, Pencil, Trash2, ArchiveRestore, FolderTree, Folder } from "lucide-react";
import type { CategoryRow, CategoryTreeOption } from "./types";

export function getCategoryColumns({
  openDetail,
  openEdit,
  setConfirmAction,
  categoryTreeOptions,
  canWriteCategories,
}: {
  openDetail: (row: CategoryRow) => void;
  openEdit: (row: CategoryRow) => void;
  setConfirmAction: (action: { kind: "delete" | "restore" | "purge"; row: CategoryRow }) => void;
  categoryTreeOptions: CategoryTreeOption[];
  canWriteCategories: boolean;
}): ColumnDef<CategoryRow>[] {
  return [
    {
      accessorKey: "name",
      header: "Tên",
      enableColumnFilter: false,
      cell: ({ row, getValue }) => (
        <button
          type="button"
          className="flex min-w-0 cursor-pointer items-center gap-2 text-left hover:text-primary transition-colors"
          onClick={() => openDetail(row.original)}
        >
          {row.depth === 0 ? (
            <FolderTree className="size-4 shrink-0 text-primary" aria-hidden />
          ) : (
            <Folder className="size-4 shrink-0 text-muted-foreground" aria-hidden />
          )}
          <span className="truncate font-medium">{String(getValue())}</span>
        </button>
      ),
    },
    {
      accessorKey: "slug",
      header: "Slug",
      cell: ({ getValue }) => (
        <span className="font-mono text-xs">{String(getValue())}</span>
      ),
      meta: { filterPlaceholder: "Lọc slug" },
    },
    {
      id: "postCount",
      accessorFn: (row) => row.postCount ?? 0,
      header: "Bài viết",
      enableColumnFilter: false,
      cell: ({ row }) => {
        const count = row.original.postCount ?? 0;
        return (
          <Badge variant={count > 0 ? "secondary" : "outline"} className="font-mono tabular-nums">
            {count}
          </Badge>
        );
      },
    },
    {
      id: "parentId",
      accessorFn: (row) => row.parentName ?? "Gốc",
      header: "Danh mục cha",
      cell: ({ row }) =>
        row.original.parentName ? (
          row.original.parentName
        ) : (
          <span className="text-muted-foreground">Gốc</span>
        ),
      meta: {
        filterVariant: "tree-multi-select",
        treeOptions: categoryTreeOptions.map((c) => ({
          value: c.id,
          label: c.name,
          children: c.subRows?.map((s) => ({
            value: s.id,
            label: s.name,
            children: s.subRows?.map((ss) => ({ value: ss.id, label: ss.name })),
          })),
        })),
      },
    },
    {
      id: "actions",
      header: "Thao tác",
      enableColumnFilter: false,
      enableSorting: false,
      meta: { disableColumnFilter: true },
      cell: ({ row }) => {
        const c = row.original;
        const childCount = c._count?.children ?? 0;
        const linkedPosts = c.postCount ?? 0;
        return (
          <div className="flex flex-wrap gap-1">
            <Button
              variant="default"
              className="gap-1"
              onClick={() => openDetail(c)}
            >
              <Eye className="size-4" /> Xem
            </Button>
            {canWriteCategories && (
              <>
                <Button
                  variant="outline"
                  className="gap-1"
                  onClick={() => openEdit(c)}
                >
                  <Pencil className="mr-1 h-4 w-4" /> Sửa
                </Button>
                <Button
                  variant="outline"
                  className="gap-1 border-destructive/40 text-destructive hover:bg-destructive/10"
                  onClick={() => setConfirmAction({ kind: "delete", row: c })}
                  disabled={childCount > 0 || linkedPosts > 0}
                >
                  <Trash2 className="h-4 w-4" /> Xóa tạm
                </Button>
              </>
            )}
          </div>
        );
      },
    },
  ];
}

export function getTrashColumns({
  setConfirmAction,
  formatDateTime,
  categoryTreeOptions,
}: {
  setConfirmAction: (action: { kind: "delete" | "restore" | "purge"; row: CategoryRow }) => void;
  formatDateTime: (date: string) => string;
  categoryTreeOptions: CategoryTreeOption[];
}): ColumnDef<CategoryRow>[] {
  return [
    {
      accessorKey: "name",
      header: "Tên",
      enableColumnFilter: false,
      cell: ({ row, getValue }) => (
        <div className="flex items-center gap-2">
          {row.depth === 0 ? (
