"use client";

import { useParams, useRouter } from "next/navigation";
import { useContactRequestDetail } from "@/hooks/queries";
import { AdminPageGuard } from "@/components/admin-page-guard";
import {
  ADMIN_PAGE_TITLE_PRIMARY_CLASS,
  ADMIN_PAGE_TITLE_ICON_CLASS,
} from "@ui/lib/layout-shell";
import { TypographyH1, TypographyH3 } from "@ui/components/typography";
import {
  FileText,
  Mail,
  Phone,
  User,
  CalendarClock,
  Pencil,
  CircleDot,
  CircleCheck,
  AlertCircle,
  UserCircle,
  MapPin,
  BookOpen,
  GraduationCap,
  Bell,
  MessageSquare,
  type LucideIcon,
} from "lucide-react";
import { Button } from "@ui/components/button";
import { Badge } from "@ui/components/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@ui/components/card";
import { formatDateTime } from "@workspace/api-client";
import type { ContactRequest } from "../_component/types";
import { CONTACT_REQUEST_STATUS_LABELS } from "../_component/types";
import { formatPhoneNumber } from "../_component/utils";
import { cn } from "@ui/lib/utils";

function ContactRequestDetailPageInner() {
  const params = useParams();
  const router = useRouter();
  const contactId = params.id as string;

  const contactQuery = useContactRequestDetail(contactId);
  const contact = contactQuery.data as ContactRequest | undefined;

  if (contactQuery.isLoading || !contact) {
    return (
      <>
        <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
          <FileText className={ADMIN_PAGE_TITLE_ICON_CLASS} aria-hidden />
          Chi tiết yêu cầu liên hệ
        </TypographyH1>
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-muted-foreground">Đang tải...</p>
          </CardContent>
        </Card>
      </>
    );
  }

  // Helper functions for status badges
  const getStatusConfig = (status: string) => {
    const configs = {
      new: {
        className: "bg-blue-50 border-blue-200 text-blue-700 dark:bg-blue-950/30 dark:border-blue-800 dark:text-blue-400",
      },
      "in-progress": {
        className: "bg-amber-50 border-amber-200 text-amber-700 dark:bg-amber-950/30 dark:border-amber-800 dark:text-amber-400",
      },
      resolved: {
        className: "bg-emerald-50 border-emerald-200 text-emerald-700 dark:bg-emerald-950/30 dark:border-emerald-800 dark:text-emerald-400",
      },
      archived: {
        className: "bg-gray-50 border-gray-200 text-gray-600 dark:bg-gray-950/30 dark:border-gray-800 dark:text-gray-400",
      },
    };
    return configs[status.toLowerCase() as keyof typeof configs] || configs.archived;
  };

  const getPriorityConfig = (priority: string) => {
    const configs = {
      HIGH: {
        label: "Cao",
        className: "bg-red-50 border-red-200 text-red-700 dark:bg-red-950/30 dark:border-red-800 dark:text-red-400",
        icon: AlertCircle,
      },
      MEDIUM: {
        label: "Trung bình",
        className: "bg-amber-50 border-amber-200 text-amber-700 dark:bg-amber-950/30 dark:border-amber-800 dark:text-amber-400",
        icon: CircleDot,
      },
      LOW: {
        label: "Thấp",
        className: "bg-gray-50 border-gray-200 text-gray-600 dark:bg-gray-950/30 dark:border-gray-800 dark:text-gray-400",
        icon: CircleDot,
      },
    };
    return configs[priority as keyof typeof configs] || configs.MEDIUM;
  };

  // Parse structured content (key-value pairs)
  const parseStructuredContent = (content: string) => {
    const lines = content.split('\n').filter(line => line.trim());
    const structured: Array<{ key: string; value: string; icon?: LucideIcon }> = [];
    let messageContent = '';

    for (const line of lines) {
      const match = line.match(/^([^:]+):\s*(.+)$/);
      if (match) {
        const [, key, value] = match;
        const iconMap: Record<string, LucideIcon> = {
          'Địa chỉ': MapPin,
          'Chương trình': BookOpen,
          'Ngành': GraduationCap,
          'Đăng ký nhận thông tin tuyển sinh': Bell,
          'Đăng ký tư vấn': Bell,
          'Nội dung': MessageSquare,
        };
        structured.push({
          key: key.trim(),
          value: value.trim(),
          icon: iconMap[key.trim()] || undefined,
        });
      } else {
        messageContent += line + '\n';
      }
    }

    return { structured, messageContent: messageContent.trim() };
  };

  const { structured, messageContent } = parseStructuredContent(contact.content || contact.message || "");

  return (
    <>
      <div className="mb-6 flex items-center justify-between">
        <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
          <FileText className={ADMIN_PAGE_TITLE_ICON_CLASS} aria-hidden />
          Chi tiết yêu cầu liên hệ
        </TypographyH1>
        <div className="flex gap-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="gap-2"
            onClick={() => router.push(`/contact-requests/${contactId}/edit`)}
          >
            <Pencil className="size-4" aria-hidden />
            Chỉnh sửa
          </Button>
        </div>
      </div>

      <div className="grid gap-6 md:grid-cols-2 pb-8">
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Thông tin liên hệ</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-start gap-3">
                <User className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden />
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-semibold text-muted-foreground">Tên</p>
                  <p className="text-sm font-medium">{contact.name}</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <Mail className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden />
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-semibold text-muted-foreground">Email</p>
                  <p className="font-mono text-sm">{contact.email}</p>
                </div>
              </div>
              {contact.phone && (
                <div className="flex items-start gap-3">
                  <Phone className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden />
                  <div className="min-w-0 flex-1">
                    <p className="text-xs font-semibold text-muted-foreground">SĐT</p>
                    <p className="font-mono text-sm">{formatPhoneNumber(contact.phone)}</p>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Trạng thái xử lý</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 sm:grid-cols-2">
                <div>
                  <p className="text-xs font-semibold text-muted-foreground">Trạng thái</p>
                  <Badge
                    variant="outline"
                    className={cn("mt-1.5 font-medium", getStatusConfig(contact.status).className)}
                  >
                    {CONTACT_REQUEST_STATUS_LABELS[contact.status.toLowerCase() as keyof typeof CONTACT_REQUEST_STATUS_LABELS] || contact.status}
                  </Badge>
                </div>
                <div>
                  <p className="text-xs font-semibold text-muted-foreground">Đã đọc</p>
                  <div className="mt-1.5 flex items-center gap-1.5">
                    {contact.isRead ? (
                      <>
                        <CircleCheck className="size-4 text-emerald-600" aria-hidden />
                        <span className="text-sm font-medium text-emerald-600">Đã đọc</span>
                      </>
                    ) : (
                      <>
                        <CircleDot className="size-4 text-muted-foreground" aria-hidden />
                        <span className="text-sm text-muted-foreground">Chưa đọc</span>
                      </>
                    )}
                  </div>
                </div>
              </div>
              <div className="pt-2 border-t border-border/50">
                <p className="text-xs font-semibold text-muted-foreground">Ưu tiên</p>
                <div className="mt-1.5 flex items-center gap-1.5">
                  {(() => {
                    const config = getPriorityConfig(contact.priority || "MEDIUM");
                    const PriorityIcon = config.icon;
                    return (
                      <Badge
                        variant="outline"
                        className={cn("gap-1.5 font-medium", config.className)}
                      >
                        <PriorityIcon className="size-3" aria-hidden />
                        {config.label}
                      </Badge>
                    );
                  })()}
                </div>
              </div>
              {contact.assignedToName && (
                <div className="flex items-start gap-3 pt-2 border-t border-border/50">
                  <UserCircle className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden />
                  <div className="min-w-0 flex-1">
                    <p className="text-xs font-semibold text-muted-foreground">Người phụ trách</p>
                    <p className="text-sm font-medium">{contact.assignedToName}</p>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Thời gian</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-start gap-3">
                <CalendarClock className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden />
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-semibold text-muted-foreground">Tạo lúc</p>
                  <p className="text-sm">{formatDateTime(contact.createdAt)}</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <CalendarClock className="mt-0.5 size-4 shrink-0 text-muted-foreground" aria-hidden />
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-semibold text-muted-foreground">Cập nhật lần cuối</p>
                  <p className="text-sm">{formatDateTime(contact.updatedAt)}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        <Card className="md:col-span-2">
          <CardHeader>
            <CardTitle>Nội dung yêu cầu</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div>
              <p className="mb-2 text-xs font-semibold text-muted-foreground">Tiêu đề</p>
              <TypographyH3 className="text-base font-semibold text-foreground">
                {contact.subject}
              </TypographyH3>
            </div>
            {structured.length > 0 && (
              <div className="grid gap-3 md:grid-cols-2">
                {structured.map((item, idx) => {
                  const Icon = item.icon;
                  return (
                    <div key={idx} className="flex items-start gap-3 rounded-lg border border-border/50 bg-muted/30 p-3">
                      {Icon && <Icon className="mt-0.5 size-4 shrink-0 text-primary" aria-hidden />}
                      <div className="min-w-0 flex-1">
                        <p className="text-xs font-semibold text-muted-foreground">{item.key}</p>
                        <p className="text-sm font-medium">{item.value}</p>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
            {messageContent && (
              <div>
                <p className="mb-2 text-xs font-semibold text-muted-foreground">Nội dung</p>
                <p className="text-sm whitespace-pre-wrap bg-muted/30 rounded-lg p-4">
                  {messageContent}
                </p>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </>
  );
}

export default function ContactRequestDetailPage() {
  return (
    <AdminPageGuard roles={["super_admin", "admin"]}>
      <ContactRequestDetailPageInner />
    </AdminPageGuard>
  );
}

src/app/contact-requests/_component/colu.content:
"use client";

import type { ColumnDef } from "@tanstack/react-table";
import { ArchiveRestore, CalendarClock, CircleCheck, CircleDashed, CircleDot, Eye, Mail, MessageSquare, Pencil, Phone, Trash2, User } from "lucide-react";
import { Badge } from "@ui/components/badge";
import { Button } from "@ui/components/button";
import type { ContactRequest } from "./types";
import { CONTACT_REQUEST_STATUS_LABELS } from "./types";
import { formatPhoneNumber } from "./utils";
import { cn } from "@ui/lib/utils";

export interface ContactRequestColumnsProps {
  onView: (contact: ContactRequest) => void;
  onEdit: (contact: ContactRequest) => void;
  onDelete: (contact: ContactRequest) => void;
  busy: boolean;
}

export function getContactRequestColumns(props: ContactRequestColumnsProps): ColumnDef<ContactRequest>[] {
  const { onView, onEdit, onDelete, busy } = props;

  return [
    {
      accessorKey: "name",
      header: "Tên",
      meta: {
        filterPlaceholder: "Lọc tên…",
        className: "sticky left-0 bg-background z-10 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]",
      } as ColumnDef<ContactRequest>['meta'],
      size: 200,
      cell: ({ row }) => (
        <span className="min-w-[200px] flex min-w-0 items-center gap-2">
          <User className="size-4 shrink-0 text-primary/80" aria-hidden />
          <span className="line-clamp-3 font-medium">{row.original.name}</span>
        </span>
      ),
    },
    {
      accessorKey: "email",
      header: "Email",
      cell: ({ getValue }) => (
        <span className="flex min-w-0 items-center gap-2 font-mono text-xs text-muted-foreground">
          <Mail className="size-3.5 shrink-0 opacity-80" aria-hidden />
          <span className="line-clamp-3">{String(getValue())}</span>
        </span>
      ),
      meta: { filterPlaceholder: "Lọc email…" },
    },
    {
      accessorKey: "phone",
      header: "SĐT",
      cell: ({ getValue }) => {
        const v = getValue() as string | null | undefined;
        return v ? (
          <span className="min-w-[120px] flex items-center gap-2 font-mono text-xs tabular-nums">
            <Phone className="size-3.5 shrink-0 text-muted-foreground" aria-hidden />
            {formatPhoneNumber(v)}
          </span>
        ) : (
          <span className="min-w-[120px] flex items-center gap-1.5 text-xs text-muted-foreground">
            <Phone className="size-3.5 opacity-40" aria-hidden />—
          </span>
        );
      },
      meta: { filterPlaceholder: "Lọc SĐT…" },
    },
    {
      accessorKey: "subject",
      header: "Tiêu đề",
      cell: ({ getValue }) => (
        <span className="line-clamp-3 max-w-[300px]">{String(getValue())}</span>
      ),
      meta: { filterPlaceholder: "Lọc tiêu đề…" },
    },
    {
      accessorKey: "content",
      header: "Nội dung",
      cell: ({ row }) => {
        const content = row.original.content || row.original.message || "";

        // Parse structured content to extract only the message
        const lines = content.split('\n').filter(line => line.trim());
        let message = "";

        for (const line of lines) {
          const match = line.match(/^Nội dung:\s*(.+)$/);
          if (match) {
            message = match[1].trim();
            break;
          }
        }

        // If no "Nội dung:" found, use the whole content but exclude structured fields
        if (!message) {
          for (const line of lines) {
            const isStructuredField = line.match(/^(Địa chỉ|Chương trình|Ngành|Đăng ký|Số điện thoại|Email):/);
            if (!isStructuredField) {
              message += line + " ";
            }
          }
        }

        return (
          <span className="flex items-start gap-2 text-xs">
            <MessageSquare className="size-3.5 shrink-0 mt-0.5 text-muted-foreground" aria-hidden />
            <span className="line-clamp-3 max-w-[300px]">{message.trim() || content}</span>
          </span>
        );
      },
      meta: { filterPlaceholder: "Lọc nội dung…" },
    },
    {
      accessorKey: "address",
      header: "Địa chỉ",
      enableColumnFilter: false,
      cell: ({ row }) => {
        const content = row.original.content || row.original.message || "";
        const match = content.match(/Địa chỉ:\s*(.+?)(?:\n|$)/);
        const address = match ? match[1].trim() : "";

        if (!address) return <span className="text-muted-foreground text-xs">—</span>;

        return (
          <span className="line-clamp-3 text-xs max-w-[300px]">{address}</span>
        );
      },
    },
    {
      accessorKey: "program",
      header: "Chương trình",
      enableColumnFilter: false,
      cell: ({ row }) => {
        const content = row.original.content || row.original.message || "";
        const match = content.match(/Chương trình:\s*(.+?)(?:\n|$)/);
        const program = match ? match[1].trim() : "";

        if (!program) return <span className="text-muted-foreground text-xs">—</span>;

        return (
          <span className="line-clamp-3 text-xs max-w-[300px]">{program}</span>
        );
      },
    },
    {
      accessorKey: "major",
      header: "Ngành",
      enableColumnFilter: false,
      cell: ({ row }) => {
        const content = row.original.content || row.original.message || "";
        const match = content.match(/Ngành:\s*(.+?)(?:\n|$)/);
        const major = match ? match[1].trim() : "";

        if (!major) return <span className="text-muted-foreground text-xs">—</span>;

        return (
          <span className="line-clamp-3 text-xs max-w-[300px]">{major}</span>
        );
      },
    },
    {
      accessorKey: "status",
      header: "Trạng thái",
      cell: ({ row }) => {
        const status = row.original.status;
        const label = CONTACT_REQUEST_STATUS_LABELS[status];

        const statusConfig = {
          new: {
            icon: CircleDot,
            className: "bg-blue-50 border-blue-200 text-blue-700 dark:bg-blue-950/30 dark:border-blue-800 dark:text-blue-400",
          },
          "in-progress": {
            icon: CircleDashed,
            className: "bg-amber-50 border-amber-200 text-amber-700 dark:bg-amber-950/30 dark:border-amber-800 dark:text-amber-400",
          },
          resolved: {
            icon: CircleCheck,
            className: "bg-emerald-50 border-emerald-200 text-emerald-700 dark:bg-emerald-950/30 dark:border-emerald-800 dark:text-emerald-400",
          },
          archived: {
            icon: CircleCheck,
            className: "bg-gray-50 border-gray-200 text-gray-600 dark:bg-gray-950/30 dark:border-gray-800 dark:text-gray-400",
          },
        } as const;

        const config = statusConfig[status as keyof typeof statusConfig] || statusConfig.archived;
        const StatusIcon = config.icon;

        return (
          <Badge variant="outline" className={cn("gap-1.5 font-medium", config.className)}>
            <StatusIcon className="size-3" aria-hidden />
            {label}
          </Badge>
        );
      },
      filterFn: (row, id, v) => {
        if (v == null || v === "") return true;
        return row.getValue(id) === v;
      },
      meta: {
        filterVariant: "select",
        filterLabel: "Trạng thái",
        selectOptions: [
          { value: "new", label: "Mới" },
          { value: "in-progress", label: "Đang xử lý" },
          { value: "resolved", label: "Đã giải quyết" },
          { value: "archived", label: "Đã lưu trữ" },
        ],
      },
    },
    {
      accessorKey: "createdAt",
      header: "Ngày tạo",
      enableColumnFilter: false,
      cell: ({ getValue }) => {
        const v = getValue() as string;
        return (
          <span className="min-w-[150px] flex items-center gap-2 text-xs text-muted-foreground">
            <CalendarClock className="size-3.5 shrink-0" aria-hidden />
            {new Date(v).toLocaleString("vi-VN")}
          </span>
        );
      },
    },
    {
      id: "actions",
      header: "Thao tác",
      enableColumnFilter: false,
      enableSorting: false,
      meta: {
        disableColumnFilter: true,
        className: "sticky right-0 bg-background z-10 shadow-[-2px_0_5px_-2px_rgba(0,0,0,0.1)]",
      } as ColumnDef<ContactRequest>['meta'],
      cell: ({ row }) => {
        const contact = row.original;
        return (
          <div className="flex flex-wrap gap-1">
            <Button variant="default" size="sm" onClick={() => onView(contact)}>
              <Eye className="size-3.5" aria-hidden />
              Xem
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="h-8 gap-1 rounded-lg"
              onClick={() => onEdit(contact)}
              disabled={busy}
            >
              <Pencil className="size-3.5" aria-hidden />
              Sửa
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="h-8 gap-1 rounded-lg border-destructive/40 text-destructive hover:bg-destructive/10"
              onClick={() => onDelete(contact)}
              disabled={busy}
            >
              <Trash2 className="size-3.5" aria-hidden />
              Xóa
            </Button>
          </div>
        );
      },
    },
  ];
}

export function getTrashColumns(props: {
  onRestore: (contact: ContactRequest) => void;
  onPurge: (contact: ContactRequest) => void;
  busy: boolean;
}): ColumnDef<ContactRequest>[] {
  const { onRestore, onPurge, busy } = props;

  return [
    {
      accessorKey: "name",
      header: "Tên",
      meta: { filterPlaceholder: "Lọc tên…" },
