"use client";

import { useCallback, useEffect, useMemo } from "react";
import { useRouter, useParams } from "next/navigation";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";
import { PageSection } from "@ui/components/layout";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { api } from "@/lib/api";
import {
  PostFormShell,
  usePostForm,
  buildCategoryOptionTree,
  normalizeContentForEditor,
  toLocalInputValue,
} from "../../_component";
import { usePostDetailQuery, useCategoriesQuery, useTagsQuery } from "../../_component/_query";
import type { PostFormValues } from "../../_component";

function EditPostPageInner() {
  const router = useRouter();
  const params = useParams();
  const postId = params.id as string;
  const queryClient = useQueryClient();
  const form = usePostForm();

  const { data: post, isLoading, error, refetch } = usePostDetailQuery(api, postId);
  const categoriesQuery = useCategoriesQuery(api);
  const tagsQuery = useTagsQuery(api);

  const categoryTreeOptions = useMemo(
    () => buildCategoryOptionTree(categoriesQuery.data ?? []),
    [categoriesQuery.data],
  );

  useEffect(() => {
    if (error) {
      toast.error("Không tải được bài viết");
      router.push("/posts");
    }
  }, [error, router]);

  useEffect(() => {
    if (!post) return;
    form.reset({
      id: post.id,
      title: post.title,
      slug: post.slug,
      excerpt: post.excerpt ?? "",
      image: post.image ?? "",
      content: normalizeContentForEditor(post.content),
      published: post.published,
      publishedAt: toLocalInputValue(post.publishedAt ?? ""),
      categoryIds: post.categories.map((item) => item.id),
      tagIds: post.tags.map((item) => item.id),
    });
  }, [post, form]);

  const updateMutation = useMutation({
    mutationFn: async (input: Record<string, unknown>) =>
      api.posts.update(postId, input),
    onSuccess: async (_data, variables) => {
      await queryClient.invalidateQueries({ queryKey: ["media", "posts"] });
      toast.success(`Đã cập nhật bài viết "${(variables.title as string)?.trim()}"`);
      router.push(`/posts/${postId}`);
    },
    onError: (err: unknown) => {
      const message = err instanceof Error ? err.message : "Không thể cập nhật bài viết";
      toast.error(message);
    },
  });

  const handleSubmit = useCallback(
    async (values: PostFormValues) => {
      const payload = {
        title: values.title.trim(),
        slug: values.slug.trim() || values.title.trim().toLowerCase().replace(/\s+/g, "-"),
        excerpt: values.excerpt.trim() || null,
        image: values.image.trim() || null,
        content: values.content,
        published: values.published,
        publishedAt: values.publishedAt || null,
        categoryIds: values.categoryIds,
        tagIds: values.tagIds,
      };
      await updateMutation.mutateAsync(payload);
    },
    [updateMutation],
  );

  if (isLoading) {
    return (
      <PageSection max="full" className="min-w-0 flex items-center justify-center py-24">
        <Loader2 className="size-8 animate-spin text-muted-foreground" />
      </PageSection>
    );
  }

  if (!post) return null;

  return (
    <PageSection max="full" className="min-w-0 space-y-6">
      <PostFormShell
        form={form}
        onSubmit={handleSubmit}
        submitting={updateMutation.isPending}
        editingId={postId}
        categoryTreeOptions={categoryTreeOptions}
        tagsOptions={tagsQuery.data ?? []}
        onBack={() => router.push(`/posts/${postId}`)}
        onReset={async () => {
          await refetch();
        }}
      />
    </PageSection>
  );
}

export default function EditPostPage() {
  return (
    <AdminPageGuard roles={["super_admin", "admin", "manager"]}>
      <EditPostPageInner />
    </AdminPageGuard>
  );
}

src/app/posts/[id]/page.tsx.content:
"use client";

import { useEffect } from "react";
import { useRouter, useParams } from "next/navigation";
import { toast } from "sonner";
import {
  Loader2,
  ArrowLeft,
  Pencil,
  Calendar,
  Clock,
  User,
  ImageIcon,
} from "lucide-react";
import { PageSection } from "@ui/components/layout";
import { Badge } from "@ui/components/badge";
import { Button } from "@ui/components/button";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from "@ui/components/card";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { api } from "@/lib/api";
import { LexicalEditor } from "@thangph2146/lexical-editor";
import {
  normalizeContentForEditor,
  formatDateTime,
} from "../_component";
import { usePostDetailQuery } from "../_component/_query";
import { TypographyH1 } from "@ui/components/typography";
import {
  ADMIN_PAGE_TITLE_PRIMARY_CLASS,
} from "@ui/lib/layout-shell";

function PostDetailInner() {
  const router = useRouter();
  const params = useParams();
  const postId = params.id as string;

  const { data: post, isLoading, error } = usePostDetailQuery(api, postId);

  useEffect(() => {
    if (error) {
      toast.error("Không tải được bài viết");
      router.push("/posts");
    }
  }, [error, router]);

  if (isLoading) {
    return (
      <PageSection max="full" className="min-w-0 flex items-center justify-center py-24">
        <Loader2 className="size-8 animate-spin text-muted-foreground" />
      </PageSection>
    );
  }

  if (!post) return null;

  const content = normalizeContentForEditor(post.content);

  return (
    <PageSection max="full" className="min-w-0 space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div className="flex items-center gap-3">
          <Button
            type="button"
            variant="outline"
            onClick={() => router.push("/posts")}
          >
            <ArrowLeft className="size-4" />
            Quay lại
          </Button>
          <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
            {post.title}
          </TypographyH1>
        </div>
        <Button
          type="button"
          variant="default"
          className="gap-2 rounded-lg px-5 font-semibold"
          onClick={() => router.push(`/posts/${postId}/edit`)}
        >
          <Pencil className="size-4" />
          Chỉnh sửa
        </Button>
      </div>

      <div className="grid gap-6 lg:grid-cols-3 my-6">
        <div className="space-y-6 lg:col-span-2">
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Nội dung</CardTitle>
            </CardHeader>
            <CardContent>
              {content ? (
                <LexicalEditor value={content} readOnly />
              ) : (
                <p className="text-sm text-muted-foreground italic">
                  Bài viết chưa có nội dung
                </p>
              )}
            </CardContent>
          </Card>
        </div>

        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Trạng thái</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="flex items-center justify-between text-sm">
                <span className="text-muted-foreground">Xuất bản</span>
                {post.published ? (
                  <Badge>Đã xuất bản</Badge>
                ) : (
                  <Badge variant="outline">Bản nháp</Badge>
                )}
              </div>
              {post.publishedAt && (
                <div className="flex items-center justify-between text-sm">
                  <span className="text-muted-foreground">Ngày xuất bản</span>
                  <span className="tabular-nums">{formatDateTime(post.publishedAt)}</span>
                </div>
              )}
              <div className="flex items-center gap-2 text-sm text-muted-foreground pt-2 border-t">
                <User className="size-3.5 shrink-0" />
                <span>{post.author.name ?? post.author.email}</span>
              </div>
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Calendar className="size-3.5 shrink-0" />
                <span>Tạo: {formatDateTime(post.createdAt)}</span>
              </div>
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Clock className="size-3.5 shrink-0" />
                <span>Cập nhật: {formatDateTime(post.updatedAt)}</span>
              </div>
            </CardContent>
          </Card>

          {post.excerpt && (
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Tóm tắt</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-sm text-muted-foreground">{post.excerpt}</p>
              </CardContent>
            </Card>
          )}

          {post.image && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-base">
                  <ImageIcon className="size-4" />
                  Ảnh đại diện
                </CardTitle>
              </CardHeader>
              <CardContent>
                <img
                  src={post.image}
                  alt={post.title}
                  className="max-h-96 w-full rounded-lg object-cover"
                />
              </CardContent>
            </Card>
          )}

          <Card>
            <CardHeader>
              <CardTitle className="text-base">Danh mục</CardTitle>
