"use client";

import { useForm } from "react-hook-form";
import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import { createSerializedEditorState, createParagraphNode } from "../utils";

export const postFormSchema = z.object({
  id: z.string().optional(),
  title: z.string().min(1, "Tiêu đề không được để trống"),
  slug: z.string(),
  excerpt: z.string(),
  image: z.string(),
  content: z.record(z.any()),
  published: z.boolean(),
  publishedAt: z.string(),
  categoryIds: z.array(z.string()),
  tagIds: z.array(z.string()),
});

export type PostFormValues = z.infer<typeof postFormSchema>;

const EMPTY_VALUES: PostFormValues = {
  title: "",
  slug: "",
  excerpt: "",
  image: "",
  content: createSerializedEditorState([createParagraphNode()]),
  published: false,
  publishedAt: "",
  categoryIds: [],
  tagIds: [],
};

export function usePostForm(defaultValues?: Partial<PostFormValues>) {
  return useForm<PostFormValues>({
    resolver: zodResolver(postFormSchema),
    defaultValues: { ...EMPTY_VALUES, ...defaultValues },
  });
}

import type { UseMutationResult } from "@tanstack/react-query";
import { useCallback } from "react";
import { toast } from "sonner";
import type { PostConfirmAction, PostListRow } from "../types";

export interface UsePostsActionsProps {
  deleteMutation: UseMutationResult<unknown, Error, string, unknown>;
  restoreMutation: UseMutationResult<PostListRow, Error, string, unknown>;
  purgeMutation: UseMutationResult<unknown, Error, string, unknown>;
  setConfirmAction: (action: PostConfirmAction | null) => void;
}

export function useHandleConfirmActionWithAction(
  deleteMutation: UseMutationResult<unknown, Error, string, unknown>,
  restoreMutation: UseMutationResult<PostListRow, Error, string, unknown>,
  purgeMutation: UseMutationResult<unknown, Error, string, unknown>,
  setConfirmAction: (action: PostConfirmAction | null) => void
) {
  return useCallback(async (confirmAction: PostConfirmAction): Promise<void> => {
    const { kind, row } = confirmAction;
    try {
      if (kind === "delete") {
        await deleteMutation.mutateAsync(row.id);
        toast.success(`Đã đưa «${row.title}» vào thùng rác`);
      } else if (kind === "restore") {
        await restoreMutation.mutateAsync(row.id);
        toast.success(`Đã khôi phục «${row.title}»`);
      } else {
        await purgeMutation.mutateAsync(row.id);
        toast.success(`Đã xóa vĩnh viễn «${row.title}»`);
      }
      setConfirmAction(null);
    } catch (error) {
      const fallback =
        kind === "delete"
          ? "Không xóa được bài viết"
          : kind === "restore"
            ? "Không khôi phục được bài viết"
            : "Không xóa hẳn được bài viết";
      toast.error(error instanceof Error ? error.message : fallback);
    }
  }, [deleteMutation, purgeMutation, restoreMutation, setConfirmAction]);
}

import type { OnChangeFn } from "@tanstack/react-table";
import type { ColumnFiltersState } from "@tanstack/react-table";
import type { Dispatch, SetStateAction } from "react";
import { useCallback } from "react";

export function useColumnFiltersChange(
  setColumnFilters: Dispatch<SetStateAction<ColumnFiltersState>>
): OnChangeFn<ColumnFiltersState> {
  return useCallback<OnChangeFn<ColumnFiltersState>>(
    (updater) => {
      setColumnFilters((prev) =>
        typeof updater === "function" ? updater(prev) : updater,
      );
    },
    [setColumnFilters],
  );
}

export function useClearListFilters(
  setColumnFilters: Dispatch<SetStateAction<ColumnFiltersState>>,
  setGlobalFilter: Dispatch<SetStateAction<string>>
) {
  return useCallback(() => {
    setColumnFilters([]);
    setGlobalFilter("");
  }, [setColumnFilters, setGlobalFilter]);
}

export function useClearTrashFilters(
  setTrashGlobalFilter: Dispatch<SetStateAction<string>>,
  setTrashColumnFilters?: Dispatch<SetStateAction<ColumnFiltersState>>
) {
  return useCallback(() => {
    setTrashGlobalFilter("");
    setTrashColumnFilters?.([]);
  }, [setTrashGlobalFilter, setTrashColumnFilters]);
}

