"use client";

import { useParams, useRouter } from "next/navigation";
import { useEffect } from "react";
import { useStaffForm, useStaffMutations } from "../../_component";
import { StaffFormShell } from "../../_component/_form";
import { useStaffProfile } from "@/hooks/queries";
import { useRbacCatalog } from "@/hooks/queries";
import { useAuth } from "@/providers/auth-provider";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { ADMIN_PAGE_TITLE_FORM_CLASS, ADMIN_PAGE_TITLE_ICON_SM_CLASS } from "@ui/lib/layout-shell";
import { TypographyH1 } from "@ui/components/typography";
import { Pencil } from "lucide-react";
import { canUserAccess, PERMISSION_CODES } from "@workspace/api-client";
import { Card, CardContent } from "@ui/components/card";
import { api } from "@/lib/api";

function EditStaffPageInner() {
  const params = useParams();
  const router = useRouter();
  const { user: session } = useAuth();
  const canManageUsers =
    session != null && canUserAccess(session, PERMISSION_CODES.USERS_MANAGE);
  const { updateMutation } = useStaffMutations({ api });
  const { form, resetForm, populateForm, getPayload } = useStaffForm({ editingId: params.id as string });

  const userId = params.id as string;

  const userQuery = useStaffProfile(userId);
  const rbacQuery = useRbacCatalog({
    enabled: Boolean(session) && canManageUsers,
  });

  const user = userQuery.data;
  const roles = rbacQuery.data?.roles ?? [];

  // Populate form when user data is loaded
  useEffect(() => {
    if (user) {
      populateForm(user);
    }
  }, [user, populateForm]);

  const handleSubmit = async () => {
    if (!user) return;
    const isValid = await form.trigger();
    if (!isValid) {
      return;
    }

    const payload = getPayload();
    try {
      await updateMutation.mutateAsync({ id: user.id, input: payload });
      router.push(`/staff/${userId}`);
    } catch {
      // Error handled by mutation
    }
  };

  const handleCancel = () => {
    resetForm();
    router.push(`/staff/${userId}`);
  };

  if (!session || !canManageUsers) {
    return (
      <>
        <TypographyH1 className={ADMIN_PAGE_TITLE_FORM_CLASS}>
          <Pencil className={ADMIN_PAGE_TITLE_ICON_SM_CLASS} aria-hidden />
          Sửa nhân sự
        </TypographyH1>
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-muted-foreground">Không có quyền truy cập</p>
          </CardContent>
        </Card>
      </>
    );
  }

  if (userQuery.isLoading || !user) {
    return (
      <>
        <TypographyH1 className={ADMIN_PAGE_TITLE_FORM_CLASS}>
          <Pencil className={ADMIN_PAGE_TITLE_ICON_SM_CLASS} aria-hidden />
          Sửa nhân sự
        </TypographyH1>
        <div className="py-12 text-center">
          <p className="text-muted-foreground">Đang tải...</p>
        </div>
      </>
    );
  }

  return (
    <StaffFormShell
      isEdit={true}
      form={form}
      roles={roles}
      onSubmit={handleSubmit}
      onCancel={handleCancel}
      submitting={updateMutation.isPending}
    />
  );
}

export default function EditStaffPage() {
  return (
    <AdminPageGuard roles={["super_admin", "admin"]}>
      <EditStaffPageInner />
    </AdminPageGuard>
  );
}

src/app/staff/_component/columns.tsx.content:
import type { ColumnDef } from "@tanstack/react-table";
import { ArchiveRestore, CalendarClock, CheckCircle2, Eye, Lock, Mail, Pencil, Phone, ShieldHalf, Trash2, UserCircle } from "lucide-react";
import { Badge } from "@ui/components/badge";
import { Button } from "@ui/components/button";
import { isSuperAdminRoleCode } from "@workspace/api-client";
import type { User } from "@/lib/api";

export interface StaffColumnsProps {
  onView: (user: User) => void;
  onEdit: (user: User) => void;
  onDelete: (user: User) => void;
  busy: boolean;
  currentUserId?: string;
  roleOptions?: { value: string; label: string }[];
}

export function getStaffColumns(props: StaffColumnsProps): ColumnDef<User>[] {
  const { onView, onEdit, onDelete, busy, currentUserId, roleOptions } = props;

  return [
    {
      accessorKey: "fullName",
      header: "Họ tên",
      meta: { filterPlaceholder: "Lọc họ tên…" },
      cell: ({ row }) => (
        <span className="flex min-w-0 items-center gap-2">
          <UserCircle
            className="size-4 shrink-0 text-primary/80"
            aria-hidden
          />
          <span className="truncate font-medium">
            {row.original.fullName}
          </span>
        </span>
      ),
    },
    {
      accessorKey: "email",
      header: "Email",
      cell: ({ getValue }) => (
        <span className="flex min-w-0 items-center gap-2 font-mono text-xs text-muted-foreground">
          <Mail className="size-3.5 shrink-0 opacity-80" aria-hidden />
          <span className="truncate">{String(getValue())}</span>
        </span>
      ),
      meta: { filterPlaceholder: "Lọc email…" },
    },
    {
      accessorKey: "phone",
      header: "SĐT",
      cell: ({ getValue }) => {
        const v = getValue() as string | null | undefined;
        return v ? (
          <span className="flex items-center gap-2 font-mono text-xs tabular-nums">
            <Phone
              className="size-3.5 shrink-0 text-muted-foreground"
              aria-hidden
            />
            {v}
          </span>
        ) : (
          <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
            <Phone className="size-3.5 opacity-40" aria-hidden />—
          </span>
        );
      },
      meta: { filterPlaceholder: "Lọc SĐT…" },
    },
    {
      id: "roles",
      accessorFn: (u) =>
        u.roles.length === 0 ? "" : u.roles.map((r) => r.name).join("; "),
      header: "Vai trò",
      cell: ({ row }) => {
        const u = row.original;
        if (u.roles.length === 0) {
          return (
            <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <ShieldHalf
                className="size-3.5 shrink-0 opacity-60"
                aria-hidden
              />
              —
            </span>
          );
        }
        return (
          <div className="flex flex-wrap gap-1">
            {u.roles.map((r) => (
              <Badge
                key={r.code}
                variant={
                  isSuperAdminRoleCode(r.code) ? "default" : "secondary"
                }
                className="text-xs font-normal"
              >
                {r.name}
              </Badge>
            ))}
          </div>
        );
      },
      enableColumnFilter: true,
      enableSorting: false,
      filterFn: () => true,
      meta: {
        filterVariant: "select",
        filterLabel: "Vai trò",
        selectOptions: roleOptions ?? [],
      },
    },
    {
      id: "isActive",
      accessorFn: (u) => (u.isActive ? "true" : "false"),
      header: "Trạng thái",
      cell: ({ row }) =>
        row.original.isActive ? (
          <Badge
            variant="outline"
            className="gap-1 border-emerald-200 pr-2 text-emerald-700"
          >
            <CheckCircle2 className="size-3.5 shrink-0" aria-hidden />
            Hoạt động
          </Badge>
        ) : (
          <Badge
            variant="outline"
            className="gap-1 pr-2 text-muted-foreground"
          >
            <Lock className="size-3.5 shrink-0" aria-hidden />
            Khoá
          </Badge>
        ),
      filterFn: (row, id, v) => {
        if (v == null || v === "") return true;
        return row.getValue(id) === v;
      },
      meta: {
        filterVariant: "select",
        filterLabel: "Trạng thái",
        selectOptions: [
          { value: "true", label: "Hoạt động" },
          { value: "false", label: "Khoá" },
        ],
      },
    },
    {
      id: "actions",
      header: "Thao tác",
      enableColumnFilter: false,
      enableSorting: false,
      meta: { disableColumnFilter: true },
      cell: ({ row }) => {
        const u = row.original;
        return (
          <div className="flex flex-wrap gap-1">
            <Button
              variant="default"
              size="sm"
              onClick={() => onView(u)}
            >
              <Eye className="size-3.5" aria-hidden />
              Xem
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="h-8 gap-1 rounded-lg"
              onClick={() => onEdit(u)}
              disabled={busy}
            >
              <Pencil className="size-3.5" aria-hidden />
              Sửa
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="h-8 gap-1 rounded-lg border-destructive/40 text-destructive hover:bg-destructive/10"
              onClick={() => onDelete(u)}
              disabled={busy || String(u.id) === String(currentUserId ?? "")}
              title={
                String(u.id) === String(currentUserId ?? "")
                  ? "Không xoá tài khoản đang đăng nhập"
                  : "Xoá tạm"
              }
            >
              <Trash2 className="size-3.5" aria-hidden /> Xóa tạm
            </Button>
          </div>
        );
      },
    },
  ];
}

export function getTrashColumns(props: {
  onRestore: (user: User) => void;
  onPurge: (user: User) => void;
  busy: boolean;
}): ColumnDef<User>[] {
  const { onRestore, onPurge, busy } = props;

  return [
    {
      accessorKey: "email",
      header: "Email",
      meta: { filterPlaceholder: "Lọc email…" },
      cell: ({ getValue }) => (
        <span className="flex min-w-0 items-center gap-2 font-mono text-xs">
          <Mail
            className="size-3.5 shrink-0 text-muted-foreground"
            aria-hidden
          />
          <span className="truncate">{String(getValue())}</span>
        </span>
      ),
    },
    {
      accessorKey: "fullName",
      header: "Họ tên",
      meta: { filterPlaceholder: "Lọc họ tên…" },
      cell: ({ getValue }) => (
        <span className="flex min-w-0 items-center gap-2">
          <UserCircle
            className="size-4 shrink-0 text-muted-foreground"
            aria-hidden
          />
          <span className="truncate font-medium">{String(getValue())}</span>
        </span>
      ),
    },
    {
      accessorKey: "deletedAt",
      header: "Xóa lúc",
      enableColumnFilter: false,
      cell: ({ getValue }) => {
        const v = getValue() as string | null | undefined;
        return (
          <span className="flex items-center gap-2 text-xs text-muted-foreground">
            <CalendarClock className="size-3.5 shrink-0" aria-hidden />
            {v ? new Date(v).toLocaleString("vi-VN") : "—"}
          </span>
        );
      },
    },
    {
      id: "actions",
      header: "Thao tác",
      enableColumnFilter: false,
      enableSorting: false,
      meta: { disableColumnFilter: true },
      cell: ({ row }) => (
        <div className="flex flex-wrap justify-end gap-1">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-8 gap-1 rounded-lg"
            onClick={() => onRestore(row.original)}
            disabled={busy}
          >
            <ArchiveRestore className="size-3.5" aria-hidden />
            Khôi phục
          </Button>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-8 gap-1 rounded-lg border-destructive/40 text-destructive hover:bg-destructive/10"
            onClick={() => onPurge(row.original)}
            disabled={busy}
          >
            <Trash2 className="size-3.5" aria-hidden />
            Xóa hẳn
          </Button>
        </div>
      ),
    },
  ];
}

