  "aria-expanded:border-primary/25 aria-expanded:bg-primary/[0.05] aria-expanded:shadow-md",
  "focus-visible:outline-none focus-visible:ring-4 focus-visible:ring-ring/20 supports-[backdrop-filter]:bg-background/75",
);

const HEADER_PROFILE_AVATAR = cn(
  "flex h-10 w-10 shrink-0 items-center justify-center rounded-lg border border-primary/15 bg-gradient-to-br from-primary/15 to-primary/5",
  "text-sm font-extrabold tracking-wide text-primary shadow-inner transition-all duration-200",
  "group-hover:border-primary/25 group-hover:from-primary/20 group-hover:to-primary/10 group-hover:shadow-sm",
  "group-aria-expanded:border-primary/25 group-aria-expanded:from-primary/20 group-aria-expanded:to-primary/10",
);

function initials(name: string): string {
  const p = name.trim().split(/\s+/).filter(Boolean);
  if (p.length === 0) return "?";
  if (p.length === 1) return p[0].slice(0, 2).toUpperCase();
  return (p[0][0] + p[p.length - 1][0]).toUpperCase();
}

function roleSummary(user: { roles: { name: string; displayName: string }[] }): string {
  if (!user.roles.length) return "Chưa gán vai trò";
  return user.roles.map((r) => r.displayName || r.name).join(" · ");
}

function AuthLoadingScreen({ message }: { message: string }) {
  return (
    <div className="min-h-screen flex items-center justify-center bg-muted/30 text-muted-foreground text-sm">
      {message}
    </div>
  );
}

export function AdminShell({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const clientReady = useClientReady();
  const { user } = useAuth();
  const { theme, setTheme } = useTheme();
  const { size, setSize } = useTextSize();
  const displayName = user?.name?.trim() || user?.email || "Người dùng HUB";
  const onAuthRoute = isAuthPath(pathname);
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [mobileNavOpen, setMobileNavOpen] = useState(false);

  useEffect(() => {
    try {
      setSidebarCollapsed(localStorage.getItem(SIDEBAR_COLLAPSED_KEY) === "1");
    } catch {
      /* ignore */
    }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem(SIDEBAR_COLLAPSED_KEY, sidebarCollapsed ? "1" : "0");
    } catch {
      /* ignore */
    }
  }, [sidebarCollapsed]);

  // Force editor toolbar sticky via JS to overcome any CSS specificity issues
  useEffect(() => {
    const forceToolbarSticky = () => {
      document.querySelectorAll<HTMLElement>(".editor-toolbar").forEach((el) => {
        el.style.setProperty("position", "sticky", "important");
        el.style.setProperty("top", "-24px", "important");
      });
    };
    forceToolbarSticky();
    const timer = setTimeout(forceToolbarSticky, 500);
    const observer = new MutationObserver(forceToolbarSticky);
    observer.observe(document.body, { childList: true, subtree: true });
    return () => {
      clearTimeout(timer);
      observer.disconnect();
    };
  }, []);

  useEffect(() => {
    if (!clientReady) return;

    if (onAuthRoute) {
      if (user && canAccessStaffAdmin(user)) {
        router.replace("/");
        return;
      }
      if (user && !canAccessStaffAdmin(user)) {
        clearAdminSession();
        window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
        router.replace(`${AUTH_LOGIN_PATH}?reason=staff_only`);
      }
      return;
    }

    if (!user) {
      router.replace(AUTH_LOGIN_PATH);
      return;
    }
    if (!canAccessStaffAdmin(user)) {
      clearAdminSession();
      window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
      router.replace(`${AUTH_LOGIN_PATH}?reason=staff_only`);
    }
  }, [clientReady, onAuthRoute, user, router]);

  if (onAuthRoute) {
    if (!clientReady) {
      return <AuthLoadingScreen message="Đang tải…" />;
    }
    if (user && canAccessStaffAdmin(user)) {
      return <AuthLoadingScreen message="Đang chuyển về bảng điều khiển…" />;
    }
    return (
      <>
        <div className="fixed right-4 top-4 z-50 rounded-lg border border-border bg-background/90 p-0.5 shadow-sm backdrop-blur-sm">
          <ThemeToggle />
        </div>
        {children}
      </>
    );
  }

  if (!clientReady || !user) {
    return <AuthLoadingScreen message="Đang tải…" />;
  }

  const rolesDisplay = roleSummary(user);

  return (
    <>
    <div className="flex h-screen w-full flex-col bg-background font-sans text-foreground md:flex-row">
        <Sheet open={mobileNavOpen} onOpenChange={setMobileNavOpen}>
          <SheetContent
            id="admin-mobile-nav"
            side="left"
            showCloseButton
            className={ADMIN_SHEET_NAV_CLASS}
          >
            <SheetHeader className="sr-only">
              <SheetTitle>Menu điều hướng</SheetTitle>
            </SheetHeader>
            <MobileSidebarPanel onNavigate={() => setMobileNavOpen(false)} />
          </SheetContent>
        </Sheet>

        <Sidebar collapsed={sidebarCollapsed} />

        <div className="flex min-w-0 flex-1 flex-col overflow-hidden">
          <header data-admin-header="true" className="sticky top-0 z-10 flex min-h-16 shrink-0 items-center justify-between border-b border-border/70 bg-background/85 px-3 shadow-[0_1px_0_0_hsl(var(--border)/0.4)] backdrop-blur-xl supports-[backdrop-filter]:bg-background/75 sm:min-h-[4.5rem] sm:px-5 lg:px-6">
            <div className="flex min-w-0 items-center gap-2 sm:gap-3">
              <Button
                type="button"
                variant="outline"
                size="icon"
                className={HEADER_ICON_BTN_MOBILE}
                onClick={() => setMobileNavOpen(true)}
                aria-label="Mở menu điều hướng"
                aria-expanded={mobileNavOpen}
                aria-controls="admin-mobile-nav"
              >
                <Menu aria-hidden className="size-5" />
              </Button>
              <TypographyH2 className="shrink-0 truncate text-lg font-bold text-primary sm:text-xl md:hidden">
                B2B Admin
              </TypographyH2>
              <Button
                type="button"
                variant="outline"
                size="icon"
                className={HEADER_ICON_BTN_DESKTOP}
                onClick={() => setSidebarCollapsed((c) => !c)}
                aria-label={sidebarCollapsed ? "Mở sidebar" : "Thu gọn sidebar"}
                title={sidebarCollapsed ? "Mở sidebar" : "Thu gọn sidebar"}
                aria-pressed={!sidebarCollapsed}
              >
                {sidebarCollapsed ? (
                  <PanelLeft aria-hidden className="size-5" />
                ) : (
                  <PanelLeftClose aria-hidden className="size-5" />
                )}
              </Button>
            </div>
            <div className="flex-1" />
            <div className="flex items-center gap-2 sm:gap-3">
              <AdminNotificationBell />
              <DropdownMenu>
                <DropdownMenuTrigger
                  render={
                    <button
                      type="button"
                      className={HEADER_PROFILE_TRIGGER}
                      aria-label="Mở menu tài khoản và tuỳ chỉnh giao diện"
                    />
                  }
                >
                  <div className="hidden min-w-0 text-right sm:block">
                    <p className="max-w-[220px] truncate text-sm font-bold leading-none text-foreground">
                      {displayName}
                    </p>
                    <p
                      className={cn(
                        ADMIN_HEADER_ROLE_LINE_CLASS,
                        "mt-1 max-w-[220px] truncate text-[11px] text-muted-foreground/90",
                      )}
                      title={rolesDisplay}
                    >
                      {rolesDisplay}
                    </p>
                  </div>
                  <div className={HEADER_PROFILE_AVATAR}>
                    {initials(displayName)}
                  </div>
                  <ChevronDown className="hidden size-4 shrink-0 text-muted-foreground transition-transform duration-200 group-aria-expanded:rotate-180 sm:block" />
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-72 p-2">
                  <div className="px-2 py-2">
                    <div className="flex items-center gap-3">
                      <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg border border-primary/20 bg-primary/10 text-sm font-bold text-primary">
                        {initials(displayName)}
                      </div>
                      <div className="min-w-0">
                        <p className="truncate text-sm font-semibold text-foreground">
                          {displayName}
                        </p>
                        <p className="truncate text-xs text-muted-foreground" title={rolesDisplay}>
                          {rolesDisplay}
                        </p>
                      </div>
                    </div>
                  </div>
                  <DropdownMenuSeparator />
                  <DropdownMenuGroup>
                    <DropdownMenuItem
                      className="cursor-pointer rounded-md px-2 py-2"
                      onClick={() => router.push("/profile")}
                    >
                      <UserCircle2 className="size-4 text-muted-foreground" />
                      Hồ sơ và tài khoản
                    </DropdownMenuItem>
                  </DropdownMenuGroup>
                  <DropdownMenuSeparator />
                  <div className="px-2 py-1.5 text-xs font-medium uppercase tracking-wide text-muted-foreground">
                    Giao diện
                  </div>
                  <DropdownMenuRadioGroup
                    value={theme}
                    onValueChange={(value) =>
                      setTheme(value as "light" | "dark" | "system")
                    }
                  >
                    <DropdownMenuRadioItem
                      value="light"
                      className="cursor-pointer rounded-md px-2 py-2"
                    >
                      <Sun className="size-4 text-muted-foreground" />
                      Sáng
                    </DropdownMenuRadioItem>
                    <DropdownMenuRadioItem
                      value="dark"
                      className="cursor-pointer rounded-md px-2 py-2"
                    >
                      <Moon className="size-4 text-muted-foreground" />
                      Tối
                    </DropdownMenuRadioItem>
                    <DropdownMenuRadioItem
                      value="system"
                      className="cursor-pointer rounded-md px-2 py-2"
                    >
                      <Monitor className="size-4 text-muted-foreground" />
                      Theo hệ thống
                    </DropdownMenuRadioItem>
                  </DropdownMenuRadioGroup>
                  <DropdownMenuSeparator />
                  <div className="px-2 py-1.5 text-xs font-medium uppercase tracking-wide text-muted-foreground">
                    Cỡ chữ
                  </div>
                  <DropdownMenuRadioGroup
                    value={size}
                    onValueChange={(value) => setSize(value as "sm" | "base" | "lg")}
                  >
                    <div className="grid grid-cols-3 gap-2 px-2 pb-1 pt-1">
                      <DropdownMenuRadioItem
                        value="sm"
                        className="cursor-pointer justify-center rounded-md border border-border px-2 py-2 font-bold"
                      >
                        S
                      </DropdownMenuRadioItem>
                      <DropdownMenuRadioItem
                        value="base"
                        className="cursor-pointer justify-center rounded-md border border-border px-2 py-2 font-bold"
                      >
                        M
                      </DropdownMenuRadioItem>
                      <DropdownMenuRadioItem
                        value="lg"
                        className="cursor-pointer justify-center rounded-md border border-border px-2 py-2 font-bold"
                      >
                        L
                      </DropdownMenuRadioItem>
                    </div>
                  </DropdownMenuRadioGroup>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </header>
          <main className={ADMIN_MAIN_SCROLL_CLASS}>
            <Page as="div">
              <PageContent className={ADMIN_PAGE_CONTENT_CLASS}>
                {children}
              </PageContent>
            </Page>
          </main>
        </div>
      </div>
      <ScrollToTop />
    </>
  );
}

src/components/admin-table-pagination-fo.content:
"use client";

import { useMemo } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@ui/components/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@ui/components/select";

/** Mức page size dùng chung (API thường giới hạn ≤ 200). */
export const ADMIN_TABLE_PAGE_SIZE_OPTIONS = [10, 15, 20, 25, 50] as const;

export type AdminTablePaginationFooterProps = {
  page: number;
  pageSize: number;
  total: number;
  isLoading?: boolean;
  onPageChange: (page: number) => void;
  /** Parent nên `setPage(1)` khi đổi limit (vd. `useEffect` phụ thuộc `pageSize`). */
  onPageSizeChange: (pageSize: number) => void;
  pageSizeOptions?: readonly number[];
  emptySummary: string;
  /** VD: `đơn` → `Hiển thị 1–20 / 100 đơn`; bỏ trống chỉ hiện `… / 100`. */
  itemLabel?: string;
};

export function AdminTablePaginationFooter({
  page,
  pageSize,
  total,
  isLoading = false,
  onPageChange,
  onPageSizeChange,
  pageSizeOptions = ADMIN_TABLE_PAGE_SIZE_OPTIONS,
  emptySummary,
  itemLabel,
}: AdminTablePaginationFooterProps) {
  const totalPages = Math.max(1, Math.ceil(total / pageSize));
  const from = total === 0 ? 0 : (page - 1) * pageSize + 1;
  const to = Math.min(page * pageSize, total);

  const summary =
    total === 0
      ? emptySummary
      : itemLabel
        ? `Hiển thị ${from}–${to} / ${total} ${itemLabel}`
        : `Hiển thị ${from}–${to} / ${total}`;

  const sizeChoices = useMemo(() => {
    const set = new Set<number>([...pageSizeOptions, pageSize]);
    return [...set].sort((a, b) => a - b);
  }, [pageSize, pageSizeOptions]);

  return (
    <>
      <p className="text-sm text-muted-foreground">{summary}</p>
      <div className="flex flex-wrap items-center justify-end gap-2 sm:gap-3">
        <div className="flex items-center gap-2">
          <span className="text-xs font-medium text-muted-foreground whitespace-nowrap">
            Mỗi trang
          </span>
          <Select
            value={String(pageSize)}
            onValueChange={(v) => onPageSizeChange(Number(v))}
            disabled={isLoading}
          >
            <SelectTrigger className="h-9 w-[4.75rem] rounded-lg text-sm tabular-nums">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {sizeChoices.map((n) => (
                <SelectItem key={n} value={String(n)}>
                  {n}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="flex items-center gap-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 rounded-lg"
            disabled={page <= 1 || isLoading}
            onClick={() => onPageChange(Math.max(1, page - 1))}
          >
            <ChevronLeft className="size-4" />
            Trước
          </Button>
          <span className="px-1 text-sm tabular-nums text-muted-foreground sm:px-2">
            Trang {page} / {totalPages}
          </span>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 rounded-lg"
            disabled={page >= totalPages || isLoading}
            onClick={() => onPageChange(Math.min(totalPages, page + 1))}
          >
            Sau
            <ChevronRight className="size-4" />
          </Button>
        </div>
      </div>
    </>
  );
}

src/components/dashboard-charts.tsx.content:
"use client";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";
import { Bar, Line, Doughnut } from "react-chartjs-2";
import { Card, CardContent, CardHeader, CardTitle } from "@ui/components/card";
import type {
  DashboardMonthlyItemDto,
  DashboardCategoryItemDto,
  DashboardTopPostDto,
} from "@/types/dashboard";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  Filler,
);

const MONTH_LABELS: Record<string, string> = {
  "01": "Th1", "02": "Th2", "03": "Th3", "04": "Th4",
  "05": "Th5", "06": "Th6", "07": "Th7", "08": "Th8",
  "09": "Th9", "10": "Th10", "11": "Th11", "12": "Th12",
};

function formatMonth(key: string): string {
  const parts = key.split("-");
  const mm = parts[1] ?? "";
  return MONTH_LABELS[mm] ?? key;
}

const CHART_COLORS = {
  blue:   { bg: "rgba(59,130,246,0.15)",  border: "rgba(59,130,246,0.9)" },
  violet: { bg: "rgba(139,92,246,0.15)",  border: "rgba(139,92,246,0.9)" },
  rose:   { bg: "rgba(244,63,94,0.15)",   border: "rgba(244,63,94,0.9)" },
  amber:  { bg: "rgba(245,158,11,0.15)",  border: "rgba(245,158,11,0.9)" },
  teal:   { bg: "rgba(20,184,166,0.15)",  border: "rgba(20,184,166,0.9)" },
  slate:  { bg: "rgba(100,116,139,0.15)", border: "rgba(100,116,139,0.9)" },
};

const DOUGHNUT_COLORS = [
  "rgba(59,130,246,0.85)",
  "rgba(139,92,246,0.85)",
  "rgba(244,63,94,0.85)",
  "rgba(245,158,11,0.85)",
  "rgba(20,184,166,0.85)",
  "rgba(100,116,139,0.85)",
  "rgba(251,146,60,0.85)",
  "rgba(52,211,153,0.85)",
];

const BASE_OPTIONS = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: { display: false },
    tooltip: { mode: "index" as const, intersect: false },
  },
  scales: {
    x: {
      grid: { display: false },
      ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
    },
    y: {
      grid: { color: "rgba(100,116,139,0.08)" },
      ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
      beginAtZero: true,
    },
  },
};

export function MonthlyLineChart({ data }: { data: DashboardMonthlyItemDto[] }) {
  const labels = data.map((d) => formatMonth(d.month));

  const chartData = {
    labels,
    datasets: [
      {
        label: "Bài viết",
        data: data.map((d) => d.posts),
        borderColor: CHART_COLORS.blue.border,
        backgroundColor: CHART_COLORS.blue.bg,
        fill: true,
        tension: 0.4,
        pointRadius: 3,
        pointHoverRadius: 5,
      },
      {
        label: "Tài khoản",
        data: data.map((d) => d.users),
        borderColor: CHART_COLORS.violet.border,
        backgroundColor: CHART_COLORS.violet.bg,
        fill: true,
        tension: 0.4,
        pointRadius: 3,
        pointHoverRadius: 5,
      },
      {
        label: "Liên hệ",
        data: data.map((d) => d.contactRequests),
        borderColor: CHART_COLORS.rose.border,
        backgroundColor: CHART_COLORS.rose.bg,
        fill: true,
        tension: 0.4,
        pointRadius: 3,
        pointHoverRadius: 5,
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Hoạt động theo tháng (12 tháng gần nhất)</CardTitle>
        <div className="flex flex-wrap gap-3 pt-1">
          {chartData.datasets.map((ds) => (
            <span key={ds.label} className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <span className="inline-block size-2.5 rounded-full" style={{ background: ds.borderColor }} />
              {ds.label}
            </span>
          ))}
        </div>
      </CardHeader>
      <CardContent>
        <div className="h-64">
          <Line
            data={chartData}
            options={{
              ...BASE_OPTIONS,
              plugins: {
                ...BASE_OPTIONS.plugins,
                legend: { display: false },
                tooltip: { mode: "index", intersect: false },
              },
            }}
          />
        </div>
      </CardContent>
    </Card>
  );
}

export function MonthlyBarChart({ data }: { data: DashboardMonthlyItemDto[] }) {
  const labels = data.map((d) => formatMonth(d.month));

  const chartData = {
    labels,
    datasets: [
      {
        label: "Bài viết",
        data: data.map((d) => d.posts),
        backgroundColor: CHART_COLORS.blue.border,
        borderRadius: 4,
        barPercentage: 0.6,
      },
      {
        label: "Tài khoản mới",
        data: data.map((d) => d.users),
        backgroundColor: CHART_COLORS.violet.border,
        borderRadius: 4,
        barPercentage: 0.6,
      },
      {
        label: "Liên hệ",
        data: data.map((d) => d.contactRequests),
        backgroundColor: CHART_COLORS.rose.border,
        borderRadius: 4,
        barPercentage: 0.6,
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Bài viết & Tài khoản theo tháng</CardTitle>
        <div className="flex flex-wrap gap-3 pt-1">
          {chartData.datasets.map((ds) => (
            <span key={ds.label} className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <span className="inline-block size-2.5 rounded-full" style={{ background: ds.backgroundColor as string }} />
              {ds.label}
            </span>
          ))}
        </div>
      </CardHeader>
      <CardContent>
        <div className="h-64">
          <Bar data={chartData} options={BASE_OPTIONS} />
        </div>
      </CardContent>
    </Card>
  );
}

function flattenCategories(items: DashboardCategoryItemDto[]): { name: string; count: number }[] {
  const result: { name: string; count: number }[] = [];
  for (const item of items) {
    if (item.count > 0) {
      result.push({ name: item.name, count: item.count });
    }
    if (item.children?.length) {
      result.push(...flattenCategories(item.children));
    }
  }
  return result.sort((a, b) => b.count - a.count).slice(0, 8);
}

export function CategoryDoughnutChart({ data }: { data: DashboardCategoryItemDto[] }) {
  const flat = flattenCategories(data);

  if (!flat.length) {
    return (
      <Card>
        <CardHeader className="pb-3">
          <CardTitle className="text-base font-semibold">Phân bố bài viết theo danh mục</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-muted-foreground">Chưa có dữ liệu danh mục.</p>
        </CardContent>
      </Card>
    );
  }

  const chartData = {
    labels: flat.map((d) => d.name),
    datasets: [
      {
        data: flat.map((d) => d.count),
        backgroundColor: DOUGHNUT_COLORS,
        borderWidth: 2,
        borderColor: "transparent",
        hoverBorderColor: "rgba(255,255,255,0.6)",
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Phân bố bài viết theo danh mục</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
          <div className="mx-auto h-52 w-52 shrink-0">
            <Doughnut
              data={chartData}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                cutout: "62%",
                plugins: {
                  legend: { display: false },
                  tooltip: {
                    callbacks: {
                      label: (ctx) => ` ${ctx.label}: ${ctx.parsed} bài`,
                    },
                  },
                },
              }}
            />
          </div>
          <ul className="min-w-0 flex-1 space-y-1.5">
            {flat.map((item, i) => (
              <li key={item.name} className="flex items-center gap-2 text-sm">
                <span
                  className="inline-block size-2.5 shrink-0 rounded-full"
                  style={{ background: DOUGHNUT_COLORS[i % DOUGHNUT_COLORS.length] }}
                />
                <span className="min-w-0 flex-1 truncate text-muted-foreground">{item.name}</span>
                <span className="shrink-0 font-semibold tabular-nums">{item.count}</span>
              </li>
            ))}
          </ul>
        </div>
      </CardContent>
    </Card>
  );
}

export function TopPostsChart({ data }: { data: DashboardTopPostDto[] }) {
  if (!data.length) return null;

  const top = data.slice(0, 8);
  const chartData = {
    labels: top.map((p) => p.title.length > 30 ? p.title.slice(0, 30) + "…" : p.title),
    datasets: [
      {
        label: "Bình luận",
        data: top.map((p) => p.comments),
        backgroundColor: CHART_COLORS.teal.border,
        borderRadius: 4,
        barPercentage: 0.65,
      },
    ],
  };

  return (
    <Card>
      <CardHeader className="pb-3">
        <CardTitle className="text-base font-semibold">Top bài viết nhiều bình luận nhất</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="h-64">
          <Bar
            data={chartData}
            options={{
              ...BASE_OPTIONS,
              indexAxis: "y" as const,
              scales: {
                x: {
                  grid: { color: "rgba(100,116,139,0.08)" },
                  ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
                  beginAtZero: true,
                },
                y: {
                  grid: { display: false },
                  ticks: { color: "rgba(100,116,139,0.8)", font: { size: 11 } },
                },
              },
            }}
          />
        </div>
      </CardContent>
    </Card>
  );
}

