  notifications: "thông báo",
  messages: "tin nhắn",
  uploads: "tệp tải lên",
  roles: "vai trò",
}

const ACTION_LABEL_VI: Record<string, string> = {
  view: "Xem",
  view_all: "Xem tất cả",
  view_own: "Xem của mình",
  manage: "Quản lý",
  update: "Cập nhật",
  export: "Xuất",
  import: "Nhập",
  restore: "Khôi phục",
  create: "Tạo mới",
